import { MakeLogicType, actions, afterMount, connect, kea, key, listeners, path, props, propsChanged, reducers, selectors } from 'kea'
import { loaders } from 'kea-loaders'
import { combineUrl } from 'kea-router'

import api from 'lib/api'
import { teamLogic } from 'scenes/teamLogic'

import { DateRange } from '~/queries/schema/schema-general'


export interface ServiceFilterLogicProps {
    dateRange?: DateRange
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface serviceFilterLogicValues {
    currentTeamId: number | null; // teamLogic
    allServiceNames: string[];
    allServiceNamesLoading: boolean;
    search: string;
    serviceNames: string[];
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface serviceFilterLogicActions {
    loadServiceNames: () => any;
    loadServiceNamesFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    loadServiceNamesSuccess: (allServiceNames: string[], payload?: any) => {
        allServiceNames: string[];
        payload?: any;
    };
    setSearch: (search: string) => {
        search: string;
    };
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface serviceFilterLogicMeta {
    key: string;
    __keaTypeGenInternalSelectorTypes: {
        serviceNames: (allServiceNames: string[]) => string[];
    };
}

export type serviceFilterLogicType = MakeLogicType<serviceFilterLogicValues, serviceFilterLogicActions, ServiceFilterLogicProps, serviceFilterLogicMeta>;

export const serviceFilterLogic = kea<serviceFilterLogicType>([
    path(['products', 'logs', 'frontend', 'components', 'LogsViewer', 'Filters', 'serviceFilterLogic']),
    props({} as ServiceFilterLogicProps),
    key((props) => `${props.dateRange?.date_from ?? 'all'}_${props.dateRange?.date_to ?? 'all'}`),

    connect({
        values: [teamLogic, ['currentTeamId']],
    }),

    actions({
        setSearch: (search: string) => ({ search }),
    }),

    reducers({
        search: ['' as string, { setSearch: (_, { search }) => search }],
    }),

    loaders(({ values, props: logicProps }) => ({
        allServiceNames: [
            [] as string[],
            {
                loadServiceNames: async () => {
                    const url = combineUrl(`api/environments/${values.currentTeamId}/logs/values`, {
                        key: 'service.name',
                        attribute_type: 'resource',
                        value: values.search,
                        limit: 1000,
                        ...(logicProps.dateRange ? { dateRange: JSON.stringify(logicProps.dateRange) } : {}),
                    }).url
                    // nosemgrep: prefer-codegen-api
                    const response = await api.get(url)
                    return ((response.results ?? []) as { name: string }[]).map((r) => r.name)
                },
            },
        ],
    })),

    selectors({
        serviceNames: [(s) => [s.allServiceNames], (allServiceNames: string[]): string[] => allServiceNames],
    }),

    listeners(({ actions }) => ({
        setSearch: async (_, breakpoint) => {
            await breakpoint(300)
            actions.loadServiceNames()
        },
    })),

    propsChanged(({ actions, props: newProps }, oldProps) => {
        if (
            newProps.dateRange?.date_from !== oldProps?.dateRange?.date_from ||
            newProps.dateRange?.date_to !== oldProps?.dateRange?.date_to
        ) {
            actions.loadServiceNames()
        }
    }),

    afterMount(({ actions }) => {
        actions.loadServiceNames()
    }),
])
